1	export type Item = { kind: "sword" | "amulet" };
2	
3	export type QuoteStep = { kind: "quote"; items: Item[] };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: QuoteStep[];
8	};
9	
10	export type ScenarioResult = {
11	  results: unknown[];
12	};
13	
14	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
15	  sword: 100,
16	  amulet: 60,
17	};
18	
19	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
20	const PROCESSING_FEE = 5;
21	
22	export function processScenario(scenario: Scenario): ScenarioResult {
23	  const results = scenario.steps.map((step) => {
24	    const item = step.items[0];
25	    const basePremium = BASE_PREMIUM_BY_ITEM[item.kind];
26	    const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
27	    const premium = basePremium + surcharge + PROCESSING_FEE;
28	    return { kind: "quote", premium };
29	  });
30	  return { results };
31	}
32

